"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[610],{9140:e=>{e.exports=JSON.parse('{"functions":[{"name":"run","desc":"Executes a tree produced by LuauParser.\\n\\nReturns a [Completion] describing how the script finished: `kind` is\\n`\\"Normal\\"` for a script that just ran, or `\\"Return\\"` if the script returned.\\nAlternatively you can specifically monitor for returns by connecting to [LuauDispatcher.UnhandledReturn].\\n\\nOptionally, you can pass in an options table of type [RuntimeOptions] to enable or disable specific parser features.\\nDefault options:\\n```lua\\nlocal runtimeOptions = {\\n\\tallowEnvironmentModifications = true,\\n\\trawGlobalEnabled = true, -- this might be the one you consider disabling\\n\\toverrideCertainGlobalsAtRuntime = true,\\n\\tinstructionLimit = 10000000,\\n\\tnoEnv = false,\\n\\tallowConsoleOutput = true,\\n}\\n```\\n\\nYou may also pass in arguments to the script by passing them in after the options table.\\nEx.\\n\\n```lua\\nlocal success, tree = LuauParser.parse([[\\n\\tlocal msg1, msg2 = ...\\n\\tprint(msg1..\\" \\"..msg2)\\n]])\\nlocal completion = Dispatcher.run(tree, {}, \\"Hello\\", \\"World\\")\\n```","params":[{"name":"tree","desc":"a parsed tree from LuauParser","lua_type":"any"},{"name":"options","desc":"","lua_type":"RuntimeOptions?"},{"name":"...","desc":"Varargs passed to the script","lua_type":"any"}],"returns":[{"desc":"","lua_type":"Completion"}],"function_type":"static","source":{"line":1297,"path":"src/LuauDispatcher.luau"}},{"name":"evaluateNode","desc":"Evaluates a **single** node.\\n\\n:::caution\\nPrefer [LuauDispatcher.run] whenever possible.\\nUnlike [LuauDispatcher.run], this does **not** automatically check the tree for parse errors,\\nwrap execution in a `pcall`, update [LuauDispatcher.RunningCount], or fire\\n`RunningStatusChanged`, `LuauRan`, or `UnhandledReturn`","params":[{"name":"node","desc":"any single AST node","lua_type":"AstNode"},{"name":"scope","desc":"an optional scope to evaluate within","lua_type":"Scope?"},{"name":"options","desc":"","lua_type":"RuntimeOptions?"}],"returns":[{"desc":"","lua_type":"Completion | ...any"}],"function_type":"static","source":{"line":1376,"path":"src/LuauDispatcher.luau"}}],"properties":[{"name":"RunningCount","desc":"The number of ASTs currently executing inside [LuauDispatcher.run].","lua_type":"number","readonly":true,"source":{"line":136,"path":"src/LuauDispatcher.luau"}},{"name":"RunningStatusChanged","desc":"```lua\\nDispatcher.RunningStatusChanged:Connect(function(isRunning)\\n\\tprint(isRunning and \\"started\\" or \\"stopped\\")\\nend)\\n```\\nBecomes true when running count reaches 0, and false when it goes above 0.","lua_type":"ScriptSignal<boolean>","source":{"line":149,"path":"src/LuauDispatcher.luau"}},{"name":"LuauRan","desc":"Fires after [LuauDispatcher.run] AST execution.\\n```lua\\nDispatcher.LuauRan:Connect(function(success, result)\\n\\tif success then\\n\\t\\tprint(\\"success\\")\\n\\telse\\n\\t\\tprint(\\"failed\\")\\n\\tend\\nend)\\n```\\n\\n`result` is the AST that was executed, or was attempted to be executed.","lua_type":"ScriptSignal<boolean, { any }>","source":{"line":168,"path":"src/LuauDispatcher.luau"}},{"name":"UnhandledReturn","desc":"Fires when a script returns at the top level (essentially returning a value to nothing)\\n\\n```lua\\nDispatcher.UnhandledReturn:Connect(function(...)\\n\\tprint(\\"returned\\", select(\\"#\\", ...), \\"value(s):\\", ...)\\nend)\\nlocal options = { ... }\\nlocal success, tree = LuauParser.parse(\\"return 1\\", options)\\nDispatcher.run(tree)\\n\\n-- Output: returned 1 value(s): 1\\n```","lua_type":"ScriptSignal<...any>","source":{"line":187,"path":"src/LuauDispatcher.luau"}},{"name":"Errored","desc":"Fires whenever a script throws an error.\\nIt is recommended to disable allowConsoleOutput in [RuntimeOptions] when using this connection.\\nThe function that gets connected will receive the error message","lua_type":"ScriptSignal<any>","source":{"line":197,"path":"src/LuauDispatcher.luau"}},{"name":"Output","desc":"Fires whenever a script calls print.\\nThe function that gets connected will receive any argument passed to the print function\\n\\n```lua\\nDispatcher.Output:Connect(function(...)\\n\\tprint(...) -- This code would actually be redundant, but it demonstrates the functionality\\nend)\\n```","lua_type":"ScriptSignal<...any>","source":{"line":212,"path":"src/LuauDispatcher.luau"}},{"name":"Warned","desc":"Like [LuauDispatcher.Output], but for warn.","lua_type":"ScriptSignal<...any>","source":{"line":220,"path":"src/LuauDispatcher.luau"}},{"name":"LuauError","desc":"The error-formatting module the Dispatcher uses.\\nYou can call Dispatcher.LuauError.isErrors() on an AST to check if it has any issues.","lua_type":"LuauError","source":{"line":229,"path":"src/LuauDispatcher.luau"}},{"name":"globals","desc":"Add your own globals here (before running) to give them to scripts:\\n\\n```lua\\nDispatcher.globals.MyApi = MyApi\\n```\\n\\nYou can also replace any globals, if you want to do that for some reason.\\nThis will not work if trying to replace a console-printing function, such as warn, print, error, etc.\\nYou should instead connect to [LuauDispatcher.Output], [LuauDispatcher.Warned], or [LuauDispatcher.Errored].\\n\\nA script can also call the `rawglobal(name, value)` function to set a global that will stay in this table.\\nThis can be disabled when running Dispatcher.run() by passing in an options table.","lua_type":"{[string]: any}","source":{"line":248,"path":"src/LuauDispatcher.luau"}},{"name":"exprs","desc":"Registry of expression handlers.\\nIf you\'d like to play with these, change them, or add more, you might want to better understand the [Scope] library.","lua_type":"{[string]: (self: Runtime, node: any, scope: Scope) -> ...any}","source":{"line":764,"path":"src/LuauDispatcher.luau"}},{"name":"stats","desc":"Registry of statement handlers","lua_type":"{[string]: (self: Runtime, node: any, scope: Scope) -> Completion}","source":{"line":969,"path":"src/LuauDispatcher.luau"}}],"types":[{"name":"Completion","desc":"Describes how a statement or a whole [LuauDispatcher.run] call finished.","fields":[{"name":"kind","lua_type":"\\"Normal\\" | \\"Return\\" | \\"Break\\" | \\"Continue\\"","desc":""},{"name":"values","lua_type":"{ any }?","desc":"only present if kind == \\"Return\\""}],"source":{"line":347,"path":"src/LuauDispatcher.luau"}},{"name":"RuntimeOptions","desc":"","fields":[{"name":"rawGlobalEnabled","lua_type":"boolean?","desc":"Allows scripts to use the `rawglobal(name, value)` function."},{"name":"overrideCertainGlobalsAtRuntime","lua_type":"boolean?","desc":"Overrides `error`, `assert`, `warn`, `print`, and various methods from `game:GetService(\\"TestService\\")`"},{"name":"noEnv","lua_type":"boolean?","desc":"Runs the script without libs and functions from Dispatcher.globals"},{"name":"instructionLimit","lua_type":"number?","desc":"The maximum number of expressions/statements evaluated before stopping script execution (default 10,000,000)."},{"name":"allowEnvironmentModifications","lua_type":"boolean?","desc":"Allows scripts to overwrite globals in the environment."},{"name":"allowConsoleOutput","lua_type":"boolean?","desc":"If true, output functions will be able to print to the Roblox console."}],"source":{"line":1251,"path":"src/LuauDispatcher.luau"}}],"name":"LuauDispatcher","desc":"Executes a Luau AST produced by [LuauParser](https://vantoanvh.github.io/LuauParser/).\\n\\nOn average it is 10% faster than [vLuau](https://github.com/kosuke14/vLuau) and 108x slower than the native roblox engine.\\nYou can see better benchmark results on the [GitHub page](https://github.com/GoobisMoobis/LuauDispatcher)\\n\\nExample usage:\\n```lua\\nlocal Parser = require(path.to.LuauParser)\\nlocal Dispatcher = require(path.to.LuauDispatcher)\\n\\nlocal parseOptions = {\\n\\t-- any options you want to pass to Parser.parse\\n\\t-- ex.\\n\\tallowDeclarationSyntax = true,\\n\\tnoErrorLimit = true\\n}\\nlocal runtimeOptions = {\\n\\t-- any options you want to pass to Dispatcher.run\\n\\t-- if you do not pass in any options, the default options will be used\\n\\t-- defaults:\\n\\tallowEnvironmentModifications = true,\\n\\trawGlobalEnabled = true, -- this might be the one you consider disabling\\n\\toverrideCertainGlobalsAtRuntime = true,\\n\\tinstructionLimit = 10000000,\\n\\tnoEnv = false,\\n\\tallowConsoleOutput = true,\\n}\\nlocal code = [[\\n\\tprint(\\"Hello, world!\\")\\n]]\\n\\nlocal success, tree = Parser.parse(code, parseOptions)\\nlocal completion = Dispatcher.run(tree, runtimeOptions)\\nif completion.kind == \\"Normal\\" then\\n\\tprint(\\"Success!\\")\\nend\\n```\\n\\nA benefit of LuauDispatcher is, in my opinion, it is a lot easier to interface with than something like vLuau.\\nYou can add new functions in [LuauDispatcher.globals] if you want the execution environment to have more methods to work with.\\nExample:\\n\\n```lua\\nDispatcher.globals.foo = function()\\n\\tprint(\\"foo\\")\\nend\\n\\nlocal parseOptions = {\\n\\t...\\n}\\nlocal runtimeOptions = {\\n\\t...\\n}\\nlocal success, tree = Parser.parse(\\"foo()\\", parseOptions)\\nDispatcher.run(tree, runtimeOptions)\\n```\\n\\nScripts also get access to `rawglobal(name, value)` which will add a global to the environment that will persist across all scripts.\\nThis can cause issues if you are not careful, so it can be disabled in the runtime options.\\n\\nExample:\\n\\n```lua\\nlocal parseOptions = {\\n\\t...\\n}\\nlocal runtimeOptions = {\\n\\t...\\n}\\nlocal success, tree = Parser.parse(\'rawglobal(\\"foo\\", function() print(\\"Hello, world!\\") end)\', parseOptions)\\nDispatcher.run(tree, runtimeOptions)\\n\\nsuccess, tree = Parser.parse(\\"foo()\\", parseOptions)\\nDispatcher.run(tree, runtimeOptions)\\n```\\n\\nError messages are also heavily customized to be easily readable so you can track the issue better.\\n```lua\\nlocal success, tree = Parser.parse(\\"print(1 + 1\\", parseOptions)\\nDispatcher.run(tree, runtimeOptions)\\n\\n--[[\\n\\tOutput:\\n\\tLuauDispatcher:1163: \\n\\t-----ERROR FOUND-----\\n\\n\\tError 1/1\\n\\tExpected \')\' (to close \'(\' at column 6), got end of script/file\\n\\tLocation: line 1, column 12\\n\\n\\t-  Server - LuauError:40\\n\\tStack Begin  -  Studio\\n\\tScript \'ServerStorage.LuauDispatcher.LuauError\', Line 40 - function error  -  Studio - LuauError:40\\n\\tScript \'ServerStorage.LuauDispatcher\', Line 1163 - function run  -  Studio - LuauDispatcher:1163\\n\\tScript \'ServerScriptService.AST\', Line 3  -  Studio - AST:3\\n\\tStack End  -  Studio\\n]]\\n```\\n\\n:::note\\nThis library uses [FastSignal](https://devforum.roblox.com/t/fastsignal-a-consistent-signal-library/1360042) for connections.\\nIf you see the type ScriptSignal in these docs, think of a it the same as an RbxScriptSignal.","source":{"line":116,"path":"src/LuauDispatcher.luau"}}')}}]);